        fine,
        pickId,
      );
      break;
    case 'counter': {
      const bayCount = Math.max(2, Math.min(6, Math.round(spec.widthM / 0.6)));
      for (let i = 1; i < bayCount; i += 1) {
        const x = -hw + (spec.widthM * i) / bayCount;
        addPolyline(
          group,
          [
            [x, -hd],
            [x, hd],
