        [
          [-hw * 0.55, -hd],
          [hw * 0.55, -hd],
          [hw * 0.55, -hd * 0.45],
          [-hw * 0.55, -hd * 0.45],
          [-hw * 0.55, -hd],
        ],
        fine,
        pickId,
